import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { apiCall } from '../utils/api';

const AdminProducts = () => {
  const { user, token } = useAuth();
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [form, setForm] = useState({
    name: '',
    description: '',
    price: '',
    category: '',
    brand: '',
    image: '', // url string
    stock: ''
  });
  const [imageFile, setImageFile] = useState(null);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [error, setError] = useState('');

  useEffect(() => {
    if (user?.role === 'admin') {
      fetchProducts();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const fetchProducts = async () => {
    setLoading(true);
    try {
      const res = await apiCall.get('/products', {
        headers: { Authorization: `Bearer ${token}` },
        params: { admin: true }
      });
      const raw = res.data.products || [];
      // dedupe in case server returns duplicates
      const unique = Array.from(new Map(raw.map(p => [p._id, p])).values());
      setProducts(unique);
    } catch (err) {
      console.error('Error fetching products', err);
    } finally {
      setLoading(false);
    }
  };    


  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
  };

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    setImageFile(file);
  };

  const handleAdd = async (e) => {
    e.preventDefault();
    setError('');
    try {
      let config = { headers: { Authorization: `Bearer ${token}` } };
      let data;

      if (imageFile) {
        data = new FormData();
        data.append('name', form.name);
        data.append('description', form.description);
        data.append('price', parseFloat(form.price));
        data.append('category', form.category);
        data.append('brand', form.brand);
        data.append('stock', parseInt(form.stock, 10));
        // append file under same field name used by multer
        data.append('image', imageFile);
        config.headers['Content-Type'] = 'multipart/form-data';
      } else {
        data = {
          name: form.name,
          description: form.description,
          price: parseFloat(form.price),
          category: form.category,
          brand: form.brand,
          image: form.image,
          stock: parseInt(form.stock, 10)
        };
      }

      if (editingId) {
        await apiCall.put(`/products/${editingId}`, data, config);
        setEditingId(null);
        setShowForm(false);
      } else {
        await apiCall.post('/products', data, config);
        setShowForm(false);
      }

      setForm({ name: '', description: '', price: '', category: '', brand: '', image: '', stock: '' });
      setImageFile(null);
      fetchProducts();
    } catch (err) {
      console.error(editingId ? 'Failed to update product' : 'Failed to add product', err);
      // show detailed message when backend provides it
      setError(
        err.response?.data?.error ||
        err.response?.data?.message ||
        (editingId ? 'Failed to update product' : 'Failed to add product')
      );
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this product?')) return;
    try {
      await apiCall.delete(`/products/${id}`, { headers: { Authorization: `Bearer ${token}` } });
      if (editingId === id) setEditingId(null);
      fetchProducts();
    } catch (err) {
      console.error('Failed to delete', err);
    }
  };

  const handleEdit = (product) => {
    setEditingId(product._id);
    setForm({
      name: product.name,
      description: product.description || '',
      price: product.price || '',
      category: product.category || '',
      brand: product.brand || '',
      image: product.image || '',
      stock: product.stock != null ? product.stock.toString() : '',
      visible: product.visible !== false
    });
  };

  const handleToggle = async (product) => {
    const newVisible = !product.visible;
    try {
      await apiCall.put(
        `/products/${product._id}`,
        { visible: newVisible },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      // update local state directly so buttons remain responsive
      setProducts(prev => prev.map(p => p._id === product._id ? { ...p, visible: newVisible } : p));

      if (newVisible === false) {
        // disabling: clear form if we're editing this product
        if (editingId === product._id) {
          setEditingId(null);
          setForm({ name: '', description: '', price: '', category: '', brand: '', image: '', stock: '' });
          setShowForm(false);
        }
      } else {
        // enabling: always show the form for the newly enabled product
        setEditingId(product._id);
        setForm({
          name: product.name,
          description: product.description || '',
          price: product.price || '',
          category: product.category || '',
          brand: product.brand || '',
          image: product.image || '',
          stock: product.stock != null ? product.stock.toString() : '',
          visible: true
        });
        setShowForm(true);
      }
    } catch (err) {
      console.error('Failed to toggle visibility', err);
    }
  };


  if (user?.role !== 'admin') {
    return <div>Access denied.</div>;
  }

  return (
    <div className="admin-product-manager">
      <div className="manager-header">
        <h2>Product Management</h2>
      </div>

      <div className="manager-controls">
        {!showForm && !editingId && (
          <button
            className="show-add-btn"
            onClick={() => {
              setEditingId(null);
              setShowForm(true);
              setForm({ name: '', description: '', price: '', category: '', brand: '', image: '', stock: '' });
            }}
          >
            + Add New Product
          </button>
        )}
      </div>

      {(editingId || showForm) && (
        <div className="form-container">
          <form className="product-form" onSubmit={handleAdd}>
          {error && <p className="error">{error}</p>}
          <label>Name</label>
          <input name="name" placeholder="Enter product name" value={form.name} onChange={handleChange} required />
          <label>Description</label>
          <textarea name="description" placeholder="Enter description" value={form.description} onChange={handleChange} required />
          <label>Price</label>
          <input name="price" placeholder="₹0" value={form.price} onChange={handleChange} required type="number" step="0.01" />
          <label>Category</label>
          <select name="category" value={form.category} onChange={handleChange} required>
            <option value="">Select category</option>
            <option value="tv">TV</option>
            <option value="ac">AC</option>
            <option value="washing-machine">Washing Machine</option>
          </select>
          <label>Brand</label>
          <input name="brand" placeholder="Brand" value={form.brand} onChange={handleChange} />
          <label>Image URL</label>
          <input name="image" placeholder="Image link" value={form.image} onChange={handleChange} />
          <label>Or upload file</label>
          <input type="file" name="imageFile" onChange={handleFileChange} />
          <label>Stock</label>
          <input name="stock" placeholder="0" value={form.stock} onChange={handleChange} required type="number" />
          {editingId && (
            <label>
              <input
                type="checkbox"
                checked={form.visible !== false}
                onChange={e => setForm(prev => ({ ...prev, visible: e.target.checked }))}
              />
              Visible to customers
            </label>
          )}
          <div className="form-buttons">
            <button type="submit">{editingId ? 'Update Product' : 'Add Product'}</button>
            <button type="button" onClick={() => { setEditingId(null); setShowForm(false); setForm({ name: '', description: '', price: '', category: '', brand: '', image: '', stock: '' }); }}>
              Cancel
            </button>
          </div>
          </form>
        </div>
      )}

      {loading ? (
        <p>Loading...</p>
      ) : (
        <div className="product-list">
          {products.length === 0 && <p>No products available</p>}
          {products.map(p => (
            <div key={p._id} className="product-row">
              <span>
            {p.name} {p.visible ? `(${p.stock} in stock)` : '(hidden)'}
          </span>
              <button onClick={() => handleEdit(p)}>Edit</button>
              <button
                className={`toggle-btn ${p.visible ? '' : 'enable-btn'}`}
                onClick={() => handleToggle(p)}
              >
                {p.visible ? 'Disable' : 'Enable'}
              </button>
              <button onClick={() => handleDelete(p._id)}>Remove</button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default AdminProducts;
